export const SESSION_SCHEMA_VERSION = 1 as const;

import { randomUUID } from "node:crypto";
import { ControlServer, type EndpointRequest } from "./control-endpoint.ts";
import { type HarnessRpc, singleFlightAccept } from "./rpc-adapter.ts";
import {
	acquireLease,
	canWriteEvents,
	classifyLeaseStatus,
	heartbeat,
	readLease,
	releaseLease,
	type SessionLease,
} from "./session-lease.ts";
import { buildResponse, buildStateView, nextAllowedActions, submitUnavailableReason } from "./state-machine.ts";
import { appendEvent, readEvents, readSessionState, sessionPaths, writeSessionState } from "./storage.ts";
import type { Observation, PrimitiveResponse, SessionState } from "./types.ts";

const DEFAULT_TTL_MS = 30_000;
const DEFAULT_HEARTBEAT_MS = 10_000;
const DEFAULT_ACCEPTANCE_TIMEOUT_MS = 60_000;

export interface OwnerOptions {
	root: string;
	sessionId: string;
	rpc: HarnessRpc;
	ownerId?: string;
	ttlMs?: number;
	heartbeatMs?: number;
	acceptanceTimeoutMs?: number;
}

export interface OwnerStartInfo {
	ownerId: string;
	socketPath: string;
	leaseEpoch: number;
}

export class RuntimeOwner {
	readonly ownerId: string;
	#root: string;
	#sessionId: string;
	#rpc: HarnessRpc;
	#ttlMs: number;
	#heartbeatMs: number;
	#acceptanceTimeoutMs: number;
	#server: ControlServer;
	#heartbeatTimer: NodeJS.Timeout | undefined;
	#leaseEpoch = 0;
	#cursor = 0;
	#unsubscribeFrames: (() => void) | undefined;

	constructor(opts: OwnerOptions) {
		this.ownerId = opts.ownerId ?? `owner-${randomUUID()}`;
		this.#root = opts.root;
		this.#sessionId = opts.sessionId;
		this.#rpc = opts.rpc;
		this.#ttlMs = opts.ttlMs ?? DEFAULT_TTL_MS;
		this.#heartbeatMs = opts.heartbeatMs ?? DEFAULT_HEARTBEAT_MS;
		this.#acceptanceTimeoutMs = opts.acceptanceTimeoutMs ?? DEFAULT_ACCEPTANCE_TIMEOUT_MS;
		this.#server = new ControlServer(sessionPaths(this.#root, this.#sessionId).controlSock, (req) =>
			this.#handle(req),
		);
	}

	async start(): Promise<OwnerStartInfo> {
		const paths = sessionPaths(this.#root, this.#sessionId);
		const existing = await readEvents(this.#root, this.#sessionId, 0);
		this.#cursor = existing.reduce(
			(max, event) => Math.max(max, typeof event.cursor === "number" ? event.cursor : 0),
			0,
		);
		const { lease } = await acquireLease(this.#root, this.#sessionId, {
			ownerId: this.ownerId,
			pid: process.pid,
			endpoint: { kind: "unix-socket", path: paths.controlSock },
			eventsPath: paths.events,
			ttlMs: this.#ttlMs,
		});
		this.#leaseEpoch = lease.leaseEpoch;
		await this.#server.listen();
		this.#unsubscribeFrames = this.#rpc.onEventFrame?.((frame) => {
			void this.#emit("rpc_event", { frameType: typeof frame.type === "string" ? frame.type : "unknown" });
		});
		await this.#emit("owner_started", { ownerId: this.ownerId, rpcPid: this.#rpc.pid?.() ?? null });
		this.#heartbeatTimer = setInterval(() => {
			void heartbeat(this.#root, this.#sessionId, this.ownerId, this.#ttlMs).catch(() => this.stop());
		}, this.#heartbeatMs);
		this.#heartbeatTimer.unref?.();
		return { ownerId: this.ownerId, socketPath: paths.controlSock, leaseEpoch: this.#leaseEpoch };
	}

	async #loadState(): Promise<SessionState> {
		const state = await readSessionState(this.#root, this.#sessionId);
		if (!state) throw new Error(`session_not_found:${this.#sessionId}`);
		return state;
	}

	async #emit(kind: string, evidence: Record<string, unknown>): Promise<void> {
		const lease = await readLease(this.#root, this.#sessionId);
		if (!lease || !canWriteEvents(lease, this.ownerId)) return;
		const state = await readSessionState(this.#root, this.#sessionId);
		const view = state
			? buildStateView(state, true)
			: {
					sessionId: this.#sessionId,
					lifecycle: "started" as const,
					harness: "pi" as const,
					ownerLive: true,
					blockers: [],
				};
		await appendEvent(this.#root, this.#sessionId, {
			eventId: randomUUID(),
			cursor: ++this.#cursor,
			createdAt: new Date().toISOString(),
			severity: "info",
			kind,
			state: view,
			evidence,
			nextAllowedActions: nextAllowedActions(view.lifecycle, true),
			writer: { ownerId: this.ownerId, leaseEpoch: this.#leaseEpoch },
		});
	}

	async #observation(state: SessionState): Promise<Observation> {
		let rpcState = null;
		try {
			rpcState = await this.#rpc.getState();
		} catch {}
		const rpcLive = this.#rpc.isLive?.() ?? rpcState !== null;
		const submitReason = submitUnavailableReason(
			state.lifecycle,
			true,
			rpcState && (rpcState.isStreaming || rpcState.steeringQueueDepth > 0 || rpcState.followupQueueDepth > 0)
				? "rpc-not-idle"
				: rpcLive
					? null
					: "rpc-not-live",
		);
		return {
			lifecycle: state.lifecycle,
			ownerLive: true,
			cwd: state.handle.workspace,
			branch: state.handle.branch,
			gitDelta: "unknown",
			lastActivityAt: this.#rpc.lastFrameAt?.() ?? state.updatedAt,
			observedSignals: [rpcState?.isStreaming ? "streaming" : "idle"],
			risk: "normal",
			readyForSubmit: submitReason === null,
			submitUnavailableReason: submitReason,
		};
	}

	async #handle(req: EndpointRequest): Promise<unknown> {
		if (req.verb === "ping") return { ok: true, ownerId: this.ownerId, leaseEpoch: this.#leaseEpoch };
		if (req.verb === "observe") {
			const state = await this.#loadState();
			const observation = await this.#observation(state);
			return buildResponse(
				state,
				true,
				{ observation, ownerRouted: true },
				true,
				observation.submitUnavailableReason,
			);
		}
		if (req.verb === "submit") return this.#submit(req.input);
		if (req.verb === "retire") return this.#retire();
		return { ok: false, error: `owner_unsupported_verb:${req.verb}` };
	}

	async #submit(input: Record<string, unknown>): Promise<PrimitiveResponse> {
		const prompt = typeof input.prompt === "string" ? input.prompt : "";
		const state = await this.#loadState();
		if (!prompt)
			return buildResponse(state, true, { accepted: false, reason: "empty-prompt" }, false, "empty-prompt");
		const lifecycleGate = submitUnavailableReason(state.lifecycle, true);
		if (lifecycleGate)
			return buildResponse(state, true, { accepted: false, reason: lifecycleGate }, false, lifecycleGate);
		const result = await singleFlightAccept(this.#rpc, prompt, this.#acceptanceTimeoutMs);
		if (result.accepted) {
			const now = new Date().toISOString();
			const next: SessionState = {
				...state,
				lifecycle: "observing",
				updatedAt: now,
				handle: { ...state.handle, updatedAt: now },
			};
			await writeSessionState(this.#root, next);
			await this.#emit("prompt_accepted", { reason: result.reason, agentStartCursor: result.agentStartCursor });
			return buildResponse(next, true, { ...result, accepted: true });
		}
		await this.#emit("prompt_not_accepted", { reason: result.reason });
		return buildResponse(
			state,
			true,
			{ ...result, accepted: false },
			false,
			result.reason === "pre-state-not-idle" ? "rpc-not-idle" : null,
		);
	}

	async #retire(): Promise<PrimitiveResponse> {
		const state = await this.#loadState();
		const now = new Date().toISOString();
		const next: SessionState = {
			...state,
			lifecycle: "retired",
			updatedAt: now,
			handle: { ...state.handle, updatedAt: now },
		};
		await writeSessionState(this.#root, next);
		await this.#emit("owner_retired", {});
		queueMicrotask(() => void this.stop());
		return buildResponse(next, true, { retired: true });
	}

	async stop(): Promise<void> {
		this.#unsubscribeFrames?.();
		if (this.#heartbeatTimer) clearInterval(this.#heartbeatTimer);
		await this.#server.close().catch(() => undefined);
		await this.#rpc.close().catch(() => undefined);
		await releaseLease(this.#root, this.#sessionId, this.ownerId).catch(() => undefined);
	}
}

export interface ResolvedOwner {
	live: boolean;
	socketPath: string | null;
	lease: SessionLease | null;
}

export async function resolveOwner(root: string, sessionId: string): Promise<ResolvedOwner> {
	const lease = await readLease(root, sessionId);
	if (!lease) return { live: false, socketPath: null, lease: null };
	const status = classifyLeaseStatus(lease);
	const live = status === "live" || status === "expiredAlive" || status === "epermAlive";
	return { live, socketPath: lease.endpoint?.path ?? null, lease };
}

import type {
	HarnessLifecycle,
	NextAllowedAction,
	PrimitiveResponse,
	SessionState,
	SessionStateView,
} from "./types.ts";

const TERMINAL_LIFECYCLES: ReadonlySet<HarnessLifecycle> = new Set(["completed", "retired"]);
const SUBMIT_READY_LIFECYCLES: ReadonlySet<HarnessLifecycle> = new Set(["started", "observing"]);

const TRANSITIONS: Record<HarnessLifecycle, readonly HarnessLifecycle[]> = {
	new: ["started", "blocked", "retired"],
	started: ["submitted", "observing", "recovering", "blocked", "retired"],
	submitted: ["observing", "recovering", "validating", "blocked", "retired"],
	observing: ["submitted", "recovering", "validating", "finalizing", "blocked", "retired"],
	recovering: ["started", "submitted", "observing", "blocked", "retired"],
	validating: ["finalizing", "observing", "blocked", "retired"],
	finalizing: ["completed", "blocked", "retired"],
	completed: ["retired"],
	blocked: ["started", "submitted", "observing", "recovering", "validating", "retired"],
	retired: [],
};

export function isTerminal(lifecycle: HarnessLifecycle): boolean {
	return TERMINAL_LIFECYCLES.has(lifecycle);
}

export function canTransition(from: HarnessLifecycle, to: HarnessLifecycle): boolean {
	return TRANSITIONS[from]?.includes(to) ?? false;
}

export function assertTransition(from: HarnessLifecycle, to: HarnessLifecycle): void {
	if (from === to) return;
	if (!canTransition(from, to)) throw new Error(`invalid_transition:${from}->${to}`);
}

export function submitUnavailableReason(
	lifecycle: HarnessLifecycle,
	ownerLive: boolean,
	gateReason: string | null = null,
): string | null {
	if (isTerminal(lifecycle)) return `lifecycle-terminal:${lifecycle}`;
	if (lifecycle === "blocked") return "lifecycle-blocked";
	if (!SUBMIT_READY_LIFECYCLES.has(lifecycle)) return `lifecycle-not-idle:${lifecycle}`;
	if (!ownerLive) return "owner-not-live";
	return gateReason;
}

export function nextAllowedActions(
	lifecycle: HarnessLifecycle,
	ownerLive: boolean,
	options: { submitUnavailableReason?: string | null } = {},
): NextAllowedAction[] {
	const terminal = isTerminal(lifecycle);
	const actions: NextAllowedAction[] = [];
	const add = (verb: NextAllowedAction["verb"], available: boolean, reason?: string): void => {
		actions.push(available ? { verb, available } : { verb, available, reason: reason ?? "unavailable" });
	};

	add("observe", true);
	add("classify", true);
	add("events", true);
	add("monitor", true);
	add("start", false, "session-already-exists");

	const submitReason = submitUnavailableReason(lifecycle, ownerLive, options.submitUnavailableReason ?? null);
	add("submit", submitReason === null, submitReason ?? undefined);

	add("recover", !terminal, terminal ? `lifecycle-terminal:${lifecycle}` : undefined);
	add("validate", !terminal, terminal ? `lifecycle-terminal:${lifecycle}` : undefined);
	add("finalize", !terminal, terminal ? `lifecycle-terminal:${lifecycle}` : undefined);
	add("retire", lifecycle !== "retired", lifecycle === "retired" ? "already-retired" : undefined);

	return actions;
}

export function buildStateView(state: SessionState, ownerLive: boolean): SessionStateView {
	return {
		sessionId: state.sessionId,
		lifecycle: state.lifecycle,
		harness: state.harness,
		ownerLive,
		blockers: state.blockers,
	};
}

export function buildResponse<E extends Record<string, unknown>>(
	state: SessionState,
	ownerLive: boolean,
	evidence: E,
	ok = true,
	submitGateReason?: string | null,
): PrimitiveResponse<E> {
	return {
		ok,
		state: buildStateView(state, ownerLive),
		evidence,
		nextAllowedActions: nextAllowedActions(state.lifecycle, ownerLive, { submitUnavailableReason: submitGateReason }),
	};
}

import { createHash, randomBytes } from "node:crypto";
import { existsSync } from "node:fs";
import { mkdir, readFile, rm, writeFile } from "node:fs/promises";
import { tmpdir } from "node:os";
import { basename, dirname, join, resolve } from "node:path";
import { writeJsonAtomic } from "../workflows/state-writer.ts";
import type { SessionState } from "./types.ts";

const SESSION_ID_RE = /^[A-Za-z0-9][A-Za-z0-9._-]{0,127}$/;

export interface SessionPaths {
	dir: string;
	state: string;
	lease: string;
	events: string;
	receipts: string;
	receiptsDir: string;
	piSessionDir: string;
	controlSock: string;
}

export function canonicalWorkspacePath(workspace: string): string {
	return resolve(workspace);
}

export function assertSafeSessionId(id: string): void {
	if (!SESSION_ID_RE.test(id)) throw new Error(`unsafe_session_id:${id}`);
}

export function generateSessionId(prefix = "h"): string {
	const ts = new Date().toISOString().replace(/[:.]/g, "").replace("T", "-").slice(0, 15);
	return `${prefix}-${ts}-${randomBytes(4).toString("hex")}`;
}

function encodeSessionId(sessionId: string): string {
	assertSafeSessionId(sessionId);
	return encodeURIComponent(sessionId).replaceAll(".", "%2E");
}

export function resolveHarnessRoot(opts?: { root?: string; cwd?: string; env?: NodeJS.ProcessEnv }): string {
	const env = opts?.env ?? process.env;
	if (opts?.root) return resolve(opts.root);
	const fromEnv = env.PI_HARNESS_STATE_ROOT;
	if (fromEnv?.trim()) return resolve(fromEnv.trim());
	return join(opts?.cwd ?? process.cwd(), ".pi", "state", "harness");
}

export function sessionPaths(root: string, sessionId: string): SessionPaths {
	const dir = join(root, "sessions", encodeSessionId(sessionId));
	return {
		dir,
		state: join(dir, "state.json"),
		lease: join(dir, "lease.json"),
		events: join(dir, "events.jsonl"),
		receipts: join(dir, "receipts.jsonl"),
		receiptsDir: join(dir, "receipts"),
		piSessionDir: join(dir, "pi-session"),
		controlSock: controlSocketPath(root, sessionId),
	};
}

export function controlSocketPath(root: string, sessionId: string): string {
	const digest = createHash("sha256")
		.update(`${resolve(root)}\0${sessionId}`)
		.digest("hex");
	return join(tempHarnessRoot(), `${digest.slice(0, 32)}.sock`);
}

async function readJson<T>(file: string): Promise<T | null> {
	try {
		return JSON.parse(await readFile(file, "utf8")) as T;
	} catch (error) {
		const err = error as NodeJS.ErrnoException;
		if (err.code === "ENOENT") return null;
		throw error;
	}
}

export async function readSessionState(root: string, sessionId: string): Promise<SessionState | null> {
	return readJson<SessionState>(sessionPaths(root, sessionId).state);
}

export async function writeSessionState(root: string, state: SessionState): Promise<void> {
	await writeJsonAtomic(
		sessionPaths(root, state.sessionId).state,
		{ ...state },
		{ cwd: projectCwdForHarnessRoot(root) },
	);
}

function projectCwdForHarnessRoot(root: string): string | undefined {
	const marker = "/.pi/state/harness";
	const normalized = root.replaceAll("\\", "/");
	return normalized.endsWith(marker) ? root.slice(0, -marker.length) : undefined;
}

export async function appendEvent(root: string, sessionId: string, row: Record<string, unknown>): Promise<void> {
	const path = sessionPaths(root, sessionId).events;
	await mkdir(dirname(path), { recursive: true });
	let existing = "";
	try {
		existing = await readFile(path, "utf8");
	} catch (error) {
		const err = error as NodeJS.ErrnoException;
		if (err.code !== "ENOENT") throw error;
	}
	await writeFile(path, `${existing}${JSON.stringify(row)}\n`, "utf8");
}

export async function readEvents(root: string, sessionId: string, afterCursor = 0): Promise<Record<string, unknown>[]> {
	let raw = "";
	try {
		raw = await readFile(sessionPaths(root, sessionId).events, "utf8");
	} catch (error) {
		const err = error as NodeJS.ErrnoException;
		if (err.code === "ENOENT") return [];
		throw error;
	}
	const rows: Record<string, unknown>[] = [];
	for (const line of raw.split(/\r?\n/)) {
		if (!line.trim()) continue;
		const row = JSON.parse(line) as Record<string, unknown>;
		const cursor = typeof row.cursor === "number" ? row.cursor : 0;
		if (cursor > afterCursor) rows.push(row);
	}
	return rows;
}

export async function removeSession(root: string, sessionId: string): Promise<void> {
	await rm(sessionPaths(root, sessionId).dir, { recursive: true, force: true });
}

export function defaultRepoName(workspace: string): string | null {
	return existsSync(join(workspace, ".git")) ? basename(workspace) : null;
}

export function tempHarnessRoot(): string {
	return join(tmpdir(), `pi-harness-${process.getuid?.() ?? "u"}`);
}

import { createHash, randomBytes } from "node:crypto";
import { mkdir, readFile, rename, rm, writeFile } from "node:fs/promises";
import { dirname } from "node:path";
import { sessionPaths } from "./storage.ts";

export interface SessionLease {
	ownerId: string;
	sessionId: string;
	pid: number;
	leaseTokenHash: string;
	endpoint: { kind: "unix-socket"; path: string } | null;
	eventsPath: string;
	heartbeatAt: string;
	expiresAt: string;
	leaseEpoch: number;
	writer: { ownerId: string; leaseEpoch: number };
}

export type LeaseStatus = "missing" | "live" | "expiredAlive" | "dead" | "epermAlive";
type PidStatus = "alive" | "dead" | "eperm";

export class LeaseError extends Error {
	readonly code: string;

	constructor(message: string, code: string) {
		super(message);
		this.name = "LeaseError";
		this.code = code;
	}
}

function nowMs(clock?: () => number): number {
	return clock ? clock() : Date.now();
}

function hashToken(token: string): string {
	return createHash("sha256").update(token).digest("hex");
}

function pidStatus(pid: number): PidStatus {
	try {
		process.kill(pid, 0);
		return "alive";
	} catch (error) {
		const code = (error as NodeJS.ErrnoException).code;
		if (code === "EPERM") return "eperm";
		return "dead";
	}
}

async function writeLeaseAtomic(file: string, lease: SessionLease): Promise<void> {
	await mkdir(dirname(file), { recursive: true });
	const tmp = `${file}.tmp-${randomBytes(4).toString("hex")}`;
	await writeFile(tmp, `${JSON.stringify(lease, null, 2)}\n`, "utf8");
	await rename(tmp, file);
}

export async function readLease(root: string, sessionId: string): Promise<SessionLease | null> {
	try {
		return JSON.parse(await readFile(sessionPaths(root, sessionId).lease, "utf8")) as SessionLease;
	} catch (error) {
		if ((error as NodeJS.ErrnoException).code === "ENOENT") return null;
		throw error;
	}
}

export function isExpired(lease: SessionLease, clock?: () => number): boolean {
	return Date.parse(lease.expiresAt) <= nowMs(clock);
}

export function classifyLeaseStatus(lease: SessionLease | null, clock?: () => number): LeaseStatus {
	if (!lease) return "missing";
	const status = pidStatus(lease.pid);
	if (status === "dead") return "dead";
	if (status === "eperm") return "epermAlive";
	return isExpired(lease, clock) ? "expiredAlive" : "live";
}

export async function acquireLease(
	root: string,
	sessionId: string,
	opts: {
		ownerId: string;
		pid: number;
		endpoint?: SessionLease["endpoint"];
		eventsPath: string;
		ttlMs: number;
		clock?: () => number;
	},
): Promise<{ lease: SessionLease; token: string }> {
	const existing = await readLease(root, sessionId);
	if (existing && existing.ownerId !== opts.ownerId && classifyLeaseStatus(existing, opts.clock) !== "dead") {
		throw new LeaseError(`lease_held:${sessionId}`, "lease_held");
	}
	const token = randomBytes(16).toString("hex");
	const now = nowMs(opts.clock);
	const epoch = existing && existing.ownerId === opts.ownerId ? existing.leaseEpoch : (existing?.leaseEpoch ?? 0) + 1;
	const lease: SessionLease = {
		ownerId: opts.ownerId,
		sessionId,
		pid: opts.pid,
		leaseTokenHash: hashToken(token),
		endpoint: opts.endpoint ?? null,
		eventsPath: opts.eventsPath,
		heartbeatAt: new Date(now).toISOString(),
		expiresAt: new Date(now + opts.ttlMs).toISOString(),
		leaseEpoch: epoch,
		writer: { ownerId: opts.ownerId, leaseEpoch: epoch },
	};
	await writeLeaseAtomic(sessionPaths(root, sessionId).lease, lease);
	return { lease, token };
}

export async function heartbeat(
	root: string,
	sessionId: string,
	ownerId: string,
	ttlMs: number,
	clock?: () => number,
): Promise<SessionLease> {
	const lease = await readLease(root, sessionId);
	if (!lease) throw new LeaseError(`no_lease:${sessionId}`, "no_lease");
	if (lease.ownerId !== ownerId) throw new LeaseError(`not_lease_holder:${sessionId}`, "not_lease_holder");
	const now = nowMs(clock);
	const next = { ...lease, heartbeatAt: new Date(now).toISOString(), expiresAt: new Date(now + ttlMs).toISOString() };
	await writeLeaseAtomic(sessionPaths(root, sessionId).lease, next);
	return next;
}

export function canWriteEvents(lease: SessionLease, ownerId: string, clock?: () => number): boolean {
	return lease.ownerId === ownerId && !isExpired(lease, clock);
}

export async function releaseLease(root: string, sessionId: string, ownerId: string): Promise<void> {
	const lease = await readLease(root, sessionId);
	if (!lease) return;
	if (lease.ownerId !== ownerId) throw new LeaseError(`not_lease_holder:${sessionId}`, "not_lease_holder");
	await rm(sessionPaths(root, sessionId).lease, { force: true });
}

import { rm } from "node:fs/promises";
import { createServer, type Server } from "node:net";

export interface EndpointRequest {
	verb: string;
	input: Record<string, unknown>;
}

export class EndpointUnreachableError extends Error {
	constructor(message: string) {
		super(message);
		this.name = "EndpointUnreachableError";
	}
}

export class ControlServer {
	#server: Server;
	#socketPath: string;

	constructor(socketPath: string, handler: (request: EndpointRequest) => Promise<unknown> | unknown) {
		this.#socketPath = socketPath;
		this.#server = createServer((socket) => {
			let buffer = "";
			socket.setEncoding("utf8");
			socket.on("data", (chunk) => {
				buffer += chunk;
				const index = buffer.indexOf("\n");
				if (index < 0) return;
				const line = buffer.slice(0, index).trim();
				void (async () => {
					try {
						const parsed = JSON.parse(line) as EndpointRequest;
						const response = await handler(parsed);
						socket.end(`${JSON.stringify({ ok: true, response })}\n`);
					} catch (error) {
						const message = error instanceof Error ? error.message : String(error);
						socket.end(`${JSON.stringify({ ok: false, error: message })}\n`);
					}
				})();
			});
		});
	}

	async listen(): Promise<void> {
		await rm(this.#socketPath, { force: true });
		await new Promise<void>((resolve, reject) => {
			this.#server.once("error", reject);
			this.#server.listen(this.#socketPath, () => {
				this.#server.off("error", reject);
				resolve();
			});
		});
	}

	async close(): Promise<void> {
		await new Promise<void>((resolve) => this.#server.close(() => resolve()));
		await rm(this.#socketPath, { force: true }).catch(() => undefined);
	}
}

export async function callEndpoint(socketPath: string, request: EndpointRequest): Promise<unknown> {
	const { createConnection } = await import("node:net");
	return await new Promise((resolve, reject) => {
		const socket = createConnection(socketPath);
		let buffer = "";
		socket.setEncoding("utf8");
		socket.on("connect", () => socket.write(`${JSON.stringify(request)}\n`));
		socket.on("data", (chunk) => {
			buffer += chunk;
			const index = buffer.indexOf("\n");
			if (index < 0) return;
			const line = buffer.slice(0, index).trim();
			try {
				const parsed = JSON.parse(line) as { ok: boolean; response?: unknown; error?: string };
				if (parsed.ok) resolve(parsed.response);
				else reject(new Error(parsed.error ?? "endpoint_error"));
			} catch (error) {
				reject(error);
			} finally {
				socket.end();
			}
		});
		socket.on("error", (error) => reject(new EndpointUnreachableError(error.message)));
	});
}

import { type ChildProcessWithoutNullStreams, spawn } from "node:child_process";
import { randomUUID } from "node:crypto";
import { serializeJsonLine } from "../modes/rpc/jsonl.ts";

export interface RpcStateSnapshot {
	isStreaming: boolean;
	steeringQueueDepth: number;
	followupQueueDepth: number;
}

export interface HarnessRpc {
	getState(): Promise<RpcStateSnapshot>;
	sendPrompt(prompt: string): Promise<{ commandId: string; ack: boolean }>;
	eventCursor(): number;
	waitForAgentStart(afterCursor: number, timeoutMs: number): Promise<{ cursor: number } | null>;
	close(): Promise<void>;
	onEventFrame?(listener: (frame: Record<string, unknown>) => void): () => void;
	isLive?(): boolean;
	lastFrameAt?(): string | null;
	pid?(): number | null;
}

export interface AcceptanceResult {
	accepted: boolean;
	reason: string;
	commandId: string | null;
	preSubmitCursor: number;
	agentStartCursor: number | null;
	preSubmitState: RpcStateSnapshot;
}

export async function singleFlightAccept(
	rpc: HarnessRpc,
	prompt: string,
	timeoutMs: number,
): Promise<AcceptanceResult> {
	const pre = await rpc.getState();
	const preSubmitCursor = rpc.eventCursor();
	if (pre.isStreaming || pre.steeringQueueDepth > 0 || pre.followupQueueDepth > 0) {
		return {
			accepted: false,
			reason: "pre-state-not-idle",
			commandId: null,
			preSubmitCursor,
			agentStartCursor: null,
			preSubmitState: pre,
		};
	}
	const { commandId, ack } = await rpc.sendPrompt(prompt);
	if (!ack) {
		return {
			accepted: false,
			reason: "no-ack",
			commandId,
			preSubmitCursor,
			agentStartCursor: null,
			preSubmitState: pre,
		};
	}
	const started = await rpc.waitForAgentStart(preSubmitCursor, timeoutMs);
	if (!started) {
		return {
			accepted: false,
			reason: "no-agent-start-within-timeout",
			commandId,
			preSubmitCursor,
			agentStartCursor: null,
			preSubmitState: pre,
		};
	}
	return {
		accepted: true,
		reason: "protocol-ack-single-flight",
		commandId,
		preSubmitCursor,
		agentStartCursor: started.cursor,
		preSubmitState: pre,
	};
}

interface PendingResponse {
	resolve: (value: Record<string, unknown>) => void;
	reject: (error: Error) => void;
}

function defaultRpcCommand(): string[] {
	const configured = process.env.PI_HARNESS_RPC_COMMAND?.trim();
	if (configured) return configured.split(/\s+/);
	return ["pi", "--mode", "rpc"];
}

export class PiRpc implements HarnessRpc {
	#proc: ChildProcessWithoutNullStreams;
	#buffer = "";
	#cursor = 0;
	#pending = new Map<string, PendingResponse>();
	#agentStartCursors: number[] = [];
	#waiters: Array<{
		afterCursor: number;
		resolve: (value: { cursor: number } | null) => void;
		timer: NodeJS.Timeout;
	}> = [];
	#frameListeners: Array<(frame: Record<string, unknown>) => void> = [];
	#lastFrameAt: string | null = null;
	#alive = true;

	constructor(opts: { cwd: string; sessionDir: string; command?: string[]; env?: NodeJS.ProcessEnv }) {
		const command = opts.command ?? defaultRpcCommand();
		const [bin, ...baseArgs] = command;
		if (!bin) throw new Error("empty Pi RPC command");
		this.#proc = spawn(bin, baseArgs, {
			cwd: opts.cwd,
			env: { ...process.env, ...(opts.env ?? {}), PI_CODING_AGENT_SESSION_DIR: opts.sessionDir },
			stdio: ["pipe", "pipe", "pipe"],
		}) as ChildProcessWithoutNullStreams;
		this.#proc.stdout.setEncoding("utf8");
		this.#proc.stdout.on("data", (chunk) => this.#onData(String(chunk)));
		this.#proc.on("exit", () => {
			this.#alive = false;
		});
		this.#proc.on("error", () => {
			this.#alive = false;
		});
	}

	pid(): number | null {
		return this.#proc.pid ?? null;
	}

	#onData(chunk: string): void {
		this.#buffer += chunk;
		let index = this.#buffer.indexOf("\n");
		while (index >= 0) {
			const line = this.#buffer.slice(0, index).trim();
			this.#buffer = this.#buffer.slice(index + 1);
			if (line) this.#onFrame(line);
			index = this.#buffer.indexOf("\n");
		}
	}

	#onFrame(line: string): void {
		let frame: Record<string, unknown>;
		try {
			frame = JSON.parse(line) as Record<string, unknown>;
		} catch {
			return;
		}
		if (frame.type === "response") {
			const id = typeof frame.id === "string" ? frame.id : undefined;
			const pending = id ? this.#pending.get(id) : undefined;
			if (id && pending) {
				this.#pending.delete(id);
				pending.resolve(frame);
			}
			return;
		}
		this.#cursor += 1;
		this.#lastFrameAt = new Date().toISOString();
		if (frame.type === "agent_start") {
			const cursor = this.#cursor;
			this.#agentStartCursors.push(cursor);
			this.#waiters = this.#waiters.filter((waiter) => {
				if (cursor > waiter.afterCursor) {
					clearTimeout(waiter.timer);
					waiter.resolve({ cursor });
					return false;
				}
				return true;
			});
		}
		for (const listener of this.#frameListeners) {
			try {
				listener(frame);
			} catch {}
		}
	}

	#send(command: Record<string, unknown>): Promise<Record<string, unknown>> {
		const id = randomUUID();
		return new Promise((resolve, reject) => {
			this.#pending.set(id, { resolve, reject });
			this.#proc.stdin.write(serializeJsonLine({ id, ...command }), (error) => {
				if (error) {
					this.#pending.delete(id);
					reject(error);
				}
			});
		});
	}

	onEventFrame(listener: (frame: Record<string, unknown>) => void): () => void {
		this.#frameListeners.push(listener);
		return () => {
			this.#frameListeners = this.#frameListeners.filter((item) => item !== listener);
		};
	}

	isLive(): boolean {
		return this.#alive;
	}

	lastFrameAt(): string | null {
		return this.#lastFrameAt;
	}

	async getState(): Promise<RpcStateSnapshot> {
		const res = await this.#send({ type: "get_state" });
		const data = (res.data ?? {}) as Record<string, unknown>;
		return {
			isStreaming: data.isStreaming === true,
			steeringQueueDepth: typeof data.pendingMessageCount === "number" ? data.pendingMessageCount : 0,
			followupQueueDepth: 0,
		};
	}

	async sendPrompt(prompt: string): Promise<{ commandId: string; ack: boolean }> {
		const id = randomUUID();
		const res = await new Promise<Record<string, unknown>>((resolve, reject) => {
			this.#pending.set(id, { resolve, reject });
			this.#proc.stdin.write(serializeJsonLine({ id, type: "prompt", message: prompt }), (error) => {
				if (error) {
					this.#pending.delete(id);
					reject(error);
				}
			});
		});
		return { commandId: id, ack: res.success === true };
	}

	eventCursor(): number {
		return this.#cursor;
	}

	waitForAgentStart(afterCursor: number, timeoutMs: number): Promise<{ cursor: number } | null> {
		const existing = this.#agentStartCursors.find((cursor) => cursor > afterCursor);
		if (existing !== undefined) return Promise.resolve({ cursor: existing });
		return new Promise((resolve) => {
			const timer = setTimeout(() => {
				this.#waiters = this.#waiters.filter((waiter) => waiter.timer !== timer);
				resolve(null);
			}, timeoutMs);
			this.#waiters.push({ afterCursor, resolve, timer });
		});
	}

	async close(): Promise<void> {
		try {
			this.#proc.stdin.end();
		} catch {}
		this.#proc.kill();
	}
}

import { mkdir, readFile, rm, writeFile } from "node:fs/promises";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { runWorkflowCommand } from "../src/cli/workflow-command.ts";
import { buildResponse } from "../src/harness-control-plane/state-machine.ts";
import {
	generateSessionId,
	readSessionState,
	resolveHarnessRoot,
	sessionPaths,
	writeSessionState,
} from "../src/harness-control-plane/storage.ts";
import { SESSION_SCHEMA_VERSION, type SessionState } from "../src/harness-control-plane/types.ts";
import {
	appendJsonlIdempotent,
	readExistingStateForMutation,
	readFileOrLiteral,
	writeTextArtifact,
} from "../src/workflows/state-writer.ts";
import { readWorkflowState, writeWorkflowState } from "../src/workflows/workflow-state.ts";

describe("workflow runtime", () => {
	let cwd: string;

	beforeEach(async () => {
		cwd = join(tmpdir(), `pi-workflows-${Date.now()}-${Math.random().toString(36).slice(2)}`);
		await mkdir(cwd, { recursive: true });
	});

	afterEach(async () => {
		await rm(cwd, { recursive: true, force: true });
	});

	it("writes workflow state with receipt and checksum", async () => {
		const state = await writeWorkflowState(cwd, "ralplan", { current_phase: "planner", run_id: "run-1" });

		expect(state.skill).toBe("ralplan");
		expect(state.version).toBe(1);
		expect(state.active).toBe(true);
		expect(state.receipt).toMatchObject({ owner: "pi-workflow", skill: "ralplan" });
		expect((state.receipt as Record<string, unknown>).content_sha256).toMatchObject({ algorithm: "sha256" });

		const reread = await readWorkflowState(cwd, "ralplan");
		expect(reread?.run_id).toBe("run-1");
	});

	it("reports corrupt state for mutation reads", async () => {
		const path = join(cwd, ".pi", "workflows", "ralplan", "state.json");
		await mkdir(join(cwd, ".pi", "workflows", "ralplan"), { recursive: true });
		await writeFile(path, "not json", "utf8");

		const result = await readExistingStateForMutation(path);
		expect(result.kind).toBe("corrupt");
		await expect(writeWorkflowState(cwd, "ralplan", { current_phase: "planner" })).rejects.toThrow(/corrupt/);
	});

	it("rejects writes outside project .pi when cwd confinement is supplied", async () => {
		await expect(writeTextArtifact(join(cwd, "outside.md"), "nope", { cwd })).rejects.toThrow(/\.pi/);
	});

	it("supports pi workflow state as the centralized state command", async () => {
		const written = await runWorkflowCommand(
			["state", "ralplan", "write", "--input", '{"phase":"planner","active":true,"run_id":"run-2"}', "--json"],
			cwd,
		);
		expect(written.status).toBe(0);
		const writtenJson = JSON.parse(written.stdout) as { state: { current_phase?: string; run_id?: string } };
		expect(writtenJson.state.current_phase).toBe("planner");
		expect(writtenJson.state.run_id).toBe("run-2");
	});

	it("supports pi workflow state handoff and active snapshot updates", async () => {
		const handoff = await runWorkflowCommand(
			["state", "deep-interview", "handoff", "--to", "ralplan", "--json"],
			cwd,
		);
		expect(handoff.status).toBe(0);
		const handoffJson = JSON.parse(handoff.stdout) as {
			state: { active?: boolean };
			target_state: { active?: boolean };
		};
		expect(handoffJson.state.active).toBe(false);
		expect(handoffJson.target_state.active).toBe(true);

		const active = await runWorkflowCommand(["state", "active", "--json"], cwd);
		expect(active.status).toBe(0);
		const activeJson = JSON.parse(active.stdout) as { state: { active_workflows?: Array<{ skill: string }> } };
		expect(activeJson.state.active_workflows).toEqual([
			{
				skill: "ralplan",
				active: true,
				phase: "handoff",
				state_path: expect.any(String),
				updated_at: expect.any(String),
			},
		]);
	});

	it("appends JSONL idempotently", async () => {
		const path = join(cwd, ".pi", "plans", "ralplan", "run-1", "index.jsonl");
		const row = { stage: "planner", stage_n: 1, sha256: "abc" };
		const key = (entry: unknown): string | undefined => {
			if (!entry || typeof entry !== "object" || Array.isArray(entry)) return undefined;
			const record = entry as Record<string, unknown>;
			return `${record.stage}:${record.stage_n}:${record.sha256}`;
		};

		expect((await appendJsonlIdempotent(path, row, { cwd, key })).appended).toBe(true);
		expect((await appendJsonlIdempotent(path, row, { cwd, key })).appended).toBe(false);
		expect((await readFile(path, "utf8")).trim().split(/\r?\n/)).toHaveLength(1);
	});

	it("writes artifacts inside .pi", async () => {
		const path = join(cwd, ".pi", "specs", "demo.md");
		const result = await writeTextArtifact(path, "hello", { cwd });
		expect(result.sha256).toHaveLength(64);
		expect(await readFile(path, "utf8")).toBe("hello\n");
	});

	it("starts and observes workflow runtime state handles", async () => {
		const started = await runWorkflowCommand([
			"start",
			"--input",
			JSON.stringify({ workspace: cwd, sessionId: "h-test" }),
			"--json",
		]);
		expect(started.status).toBe(0);
		const startedJson = JSON.parse(started.stdout) as {
			state: { sessionId?: string; lifecycle?: string; ownerLive?: boolean };
			evidence: { handle?: { harness?: string; workspace?: string; rpcHandle?: { sessionDir?: string } } };
		};
		expect(startedJson.state).toMatchObject({ sessionId: "h-test", lifecycle: "started", ownerLive: false });
		expect(startedJson.evidence.handle).toMatchObject({ harness: "pi", workspace: cwd });
		expect(startedJson.evidence.handle?.rpcHandle?.sessionDir).toContain(".pi/state/harness");

		const observed = await runWorkflowCommand([
			"observe",
			"--input",
			JSON.stringify({ workspace: cwd, sessionId: "h-test" }),
			"--json",
		]);
		expect(observed.status).toBe(0);
		const observedJson = JSON.parse(observed.stdout) as {
			evidence: { observation?: { cwd?: string; submitUnavailableReason?: string } };
			nextAllowedActions: Array<{ verb: string; available: boolean; reason?: string }>;
		};
		expect(observedJson.evidence.observation).toMatchObject({ cwd, submitUnavailableReason: "owner-not-live" });
		expect(observedJson.nextAllowedActions).toContainEqual({
			verb: "submit",
			available: false,
			reason: "owner-not-live",
		});
	});

	it("persists a runtime state handle under .pi state", async () => {
		const root = resolveHarnessRoot({ cwd });
		const sessionId = generateSessionId();
		const paths = sessionPaths(root, sessionId);
		const now = new Date().toISOString();
		const state: SessionState = {
			schemaVersion: SESSION_SCHEMA_VERSION,
			sessionId,
			lifecycle: "started",
			harness: "pi",
			handle: {
				sessionId,
				harness: "pi",
				workspace: cwd,
				repo: null,
				branch: null,
				base: null,
				issueOrPr: null,
				processHandle: { kind: "runtime-owner", ownerId: null, pid: null },
				rpcHandle: { kind: "rpc-subprocess", pid: null, sessionDir: paths.piSessionDir },
				ownerHandle: { leasePath: paths.lease, endpoint: null, heartbeatAt: null },
				routerHandle: { kind: "default-in-owner", policy: "workflow-runtime", eventsPath: paths.events },
				viewportHandle: { kind: "event-monitor", tmuxSessionName: null, viewOnly: true },
				startedAt: now,
				updatedAt: now,
			},
			retries: {},
			blockers: [],
			createdAt: now,
			updatedAt: now,
		};

		await writeSessionState(root, state);
		expect(await readSessionState(root, sessionId)).toMatchObject({ sessionId, handle: { workspace: cwd } });
		expect(buildResponse(state, false, { handle: state.handle }).nextAllowedActions).toContainEqual({
			verb: "submit",
			available: false,
			reason: "owner-not-live",
		});
	});

	describe("readFileOrLiteral", () => {
		it("returns a short literal string as-is", async () => {
			expect(await readFileOrLiteral("just some prose", cwd)).toBe("just some prose");
		});

		it("returns multi-line markdown content as literal (regression: ENAMETOOLONG)", async () => {
			const markdown = [
				"# Plan",
				"",
				"A long multi-line plan body with enough content to exceed NAME_MAX when",
				`interpreted as a single path component. ${"x".repeat(300)}`,
			].join("\n");
			expect(await readFileOrLiteral(markdown, cwd)).toBe(markdown);
		});

		it("returns an over-long single-line string as literal", async () => {
			const long = "a".repeat(5000);
			expect(await readFileOrLiteral(long, cwd)).toBe(long);
		});

		it("reads an existing file path", async () => {
			const filePath = join(cwd, "draft.md");
			await writeFile(filePath, "# Draft\nbody\n", "utf8");
			expect(await readFileOrLiteral(filePath, cwd)).toBe("# Draft\nbody\n");
		});

		it("returns a nonexistent relative path as literal", async () => {
			expect(await readFileOrLiteral("does/not/exist.md", cwd)).toBe("does/not/exist.md");
		});
	});
});

